INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Midterm Exam Schedule Released', 'The schedule for the upcoming midterm examinations has been posted on the departmental notice board and the student portal. Please check for your respective batches.', 'fc1017d1-fc03-4b7f-9784-e3c07e117aee', '2026-06-24T11:49:32.901Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Library Renovation Notice', 'The Central Library will be undergoing renovations on the 2nd floor starting next Monday. Noise levels might be slightly higher. Sorry for the inconvenience.', '0d07788f-db2e-4fcc-9d54-bce133ed1dae', '2026-06-12T05:21:51.829Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Guest Lecture on AI', 'Join us this Friday at the Main Auditorium for a guest lecture on Generative AI by industry experts from Google. Attendance is highly encouraged for CSE students.', 'fc1017d1-fc03-4b7f-9784-e3c07e117aee', '2026-06-16T13:40:27.611Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Hackathon Registration Open', 'Registrations for NexHack 2.0 are now officially open! Form your teams of up to 4 members and register before the deadline. Exciting prizes to be won!', 'c83d5dc6-047b-4356-9d2d-4690efd5f17f', '2026-06-29T03:27:08.867Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Cafeteria Menu Update', 'Based on student feedback, we have added new healthy options to the cafeteria menu including salads and fresh juices. Check them out today!', '7f415341-7fd9-40fd-aeb7-bca0e3d5289d', '2026-06-30T06:49:15.142Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Lab Maintenance Schedule', 'Computer Lab 3 will be closed for hardware upgrades this weekend. Please ensure all your work is saved on the cloud.', '30af3eff-3079-4966-8eee-44c269d08c9a', '2026-06-15T05:56:58.150Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Campus Placements Drive', 'The annual campus placement drive will begin next month. All final year students are requested to update their resumes on the TnP portal.', '7f415341-7fd9-40fd-aeb7-bca0e3d5289d', '2026-07-07T08:58:48.103Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Sports Week Announcement', 'Get ready for the Annual Sports Week! Inter-departmental matches for Basketball, Football, and Cricket will begin from the 15th.', '0d07788f-db2e-4fcc-9d54-bce133ed1dae', '2026-07-08T22:56:37.847Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('New Parking Regulations', 'Please note the updated parking zones for students and faculty. Violators will be fined starting next week.', 'c83d5dc6-047b-4356-9d2d-4690efd5f17f', '2026-07-07T15:44:45.638Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Holiday Notice', 'The campus will remain closed this Thursday on account of the national holiday. Normal classes will resume on Friday.', 'c83d5dc6-047b-4356-9d2d-4690efd5f17f', '2026-06-28T07:34:59.499Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Research Grant Applications', 'Faculty members are invited to submit their proposals for the internal research grant for the upcoming academic year.', '353e33eb-664e-4958-9c11-c06caf87649b', '2026-07-04T04:27:17.770Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Workshop on Cloud Computing', 'A hands-on workshop on AWS Cloud Computing will be held next Saturday. Limited seats available, register soon.', 'ef429cd2-ad6a-4449-9473-d196ad9dee5a', '2026-07-07T21:26:54.561Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Blood Donation Camp', 'NSS is organizing a blood donation camp next Tuesday in the common room. Donate blood, save lives.', 'be5d427f-80fd-41f1-a702-0d1a4e37c5d0', '2026-07-03T17:55:12.340Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Hostel Curfew Reminder', 'A gentle reminder to all hostellers that the curfew timings remain 10:00 PM strictly. Late entries will require warden''s permission.', '30af3eff-3079-4966-8eee-44c269d08c9a', '2026-06-19T03:04:56.918Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Alumni Meet 2026', 'We are excited to announce the Alumni Meet next month. Students interested in volunteering can contact the faculty coordinator.', 'fc1017d1-fc03-4b7f-9784-e3c07e117aee', '2026-07-09T22:38:42.486Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Semester Fee Deadline', 'The last date to pay the semester fee without a late fine is the 25th of this month. Please clear your dues on time.', '4520a234-b1aa-413d-8789-393e3848f839', '2026-06-18T01:05:18.518Z');
INSERT INTO public.announcements (title, content, author_id, created_at) VALUES ('Coding Club Meeting', 'The weekly meeting of the Coding Club will be held at 4 PM tomorrow in Room 204. We will be discussing Dynamic Programming.', '7f415341-7fd9-40fd-aeb7-bca0e3d5289d', '2026-07-01T23:50:21.566Z');
INSERT INTO public.complaint_box (id, user_id, content, is_anonymous, urgency, category, created_at) VALUES ('57c2bd8b-aeb3-424d-90e9-b2829a93b615', 'fcdc31b9-7a2c-48b6-9a58-d2877120e325', 'The Wi-Fi in the library is extremely slow and keeps disconnecting during peak hours.', true, 'HIGH', 'IT & Network', '2026-06-26T17:04:45.103Z');
